document.addEventListener("DOMContentLoaded",()=>{const WRAP_ENABLED_CLASS="site-code-wrap-enabled";const WRAP_VIEW_CLASS="site-code-wrap-view";const WRAP_BUTTON_SELECTOR=".site-code-wrap-button";const WRAP_AVAILABLE_DATASET="siteCodeWrapAvailable";let wrapAvailabilityTimer=null;function scheduleWrapAvailabilityRefresh(delay=120,options={}){clearTimeout(wrapAvailabilityTimer);wrapAvailabilityTimer=window.setTimeout(()=>{window.requestAnimationFrame(()=>{refreshWrapAvailability(options);});},delay);}
function getSourceTable(highlight){return(highlight.querySelector(".site-code-wrap-source")||highlight.querySelector(".highlighttable:not(.site-code-wrap-view)")||highlight.querySelector(".highlighttable"));}
function moveCodeNavToHighlight(highlight){const nav=highlight.querySelector(".md-code__nav");const table=getSourceTable(highlight);if(table){table.classList.add("site-code-wrap-source");}
if(!nav){return null;}
if(nav.parentElement!==highlight){highlight.appendChild(nav);}
nav.style.position="absolute";nav.style.top="0.2rem";nav.style.right="0.5rem";nav.style.left="auto";nav.style.zIndex="1";return nav;}
function updateWrapButtons(){const isEnabled=document.documentElement.classList.contains(WRAP_ENABLED_CLASS);document.querySelectorAll(WRAP_BUTTON_SELECTOR).forEach((button)=>{const nextActionText=isEnabled?"关闭代码换行":"开启代码换行";button.classList.toggle("is-active",isEnabled);button.classList.toggle("md-code__button--active",isEnabled);button.setAttribute("aria-pressed",String(isEnabled));button.setAttribute("title",nextActionText);button.setAttribute("aria-label",nextActionText);});}
function hasHorizontalOverflow(highlight){const codeContainer=getSourceTable(highlight)?.querySelector("td.code > div");if(!codeContainer){return false;}
return codeContainer.scrollWidth-codeContainer.clientWidth>1;}
function normalizeLineNumberLayout(highlight){const sourceTable=getSourceTable(highlight);if(!sourceTable){return;}
const lineNumbersPre=sourceTable.querySelector("td.linenos pre");if(lineNumbersPre){lineNumbersPre.style.whiteSpace="normal";}
sourceTable.querySelectorAll("td.linenos .normal").forEach((lineNumber)=>{lineNumber.style.display="block";lineNumber.style.whiteSpace="nowrap";});}
function normalizeCodeLineWhitespace(highlight){const sourceTable=getSourceTable(highlight);if(!sourceTable){return;}
sourceTable.querySelectorAll('td.code pre code > span[id^="__span-"]').forEach((line)=>{Array.from(line.childNodes).forEach((node)=>{if(node.nodeType!==Node.TEXT_NODE||!node.nodeValue){return;}
const fragment=document.createDocumentFragment();const parts=node.nodeValue.split(/(\r\n|\r|\n)/);parts.forEach((part)=>{if(!part){return;}
if(/^(?:\r\n|\r|\n)$/.test(part)){fragment.appendChild(document.createTextNode(part));return;}
const textSpan=document.createElement("span");textSpan.className=/^[^\S\r\n]+$/.test(part)?"site-code-wrap-space":"site-code-wrap-text";textSpan.textContent=part;fragment.appendChild(textSpan);});node.replaceWith(fragment);});});}
function clearWrappedLineNumbers(highlight){highlight.querySelectorAll('td.code pre code > span[id^="__span-"]').forEach((line)=>{line.style.minHeight="";});highlight.querySelectorAll("td.linenos .normal").forEach((lineNumber)=>{lineNumber.style.height="";lineNumber.style.lineHeight="";});}
function syncWrappedLineNumbers(highlight){const sourceTable=getSourceTable(highlight);if(!sourceTable){return;}
normalizeLineNumberLayout(highlight);normalizeCodeLineWhitespace(highlight);clearWrappedLineNumbers(highlight);const codeLines=Array.from(sourceTable.querySelectorAll('td.code pre code > span[id^="__span-"]'));const lineNumbers=Array.from(sourceTable.querySelectorAll("td.linenos .normal"));const baselineLine=codeLines.find((line)=>line.getClientRects().length>0);const lineNumberSample=lineNumbers.find((lineNumber)=>lineNumber.getClientRects().length>0);const parsedCodeLineHeight=baselineLine?Number.parseFloat(window.getComputedStyle(baselineLine).lineHeight):Number.NaN;const parsedLineNumberHeight=lineNumberSample?Number.parseFloat(window.getComputedStyle(lineNumberSample).lineHeight):Number.NaN;const baselineHeight=Number.isFinite(parsedCodeLineHeight)&&parsedCodeLineHeight>0?parsedCodeLineHeight:Number.isFinite(parsedLineNumberHeight)&&parsedLineNumberHeight>0?parsedLineNumberHeight:0;const wrapThreshold=0.5;codeLines.forEach((line)=>{line.style.minHeight=line.textContent.trim()===""?`${baselineHeight}px`:"";});const lineHeights=codeLines.map((line)=>line.getBoundingClientRect().height);codeLines.forEach((line,index)=>{const lineNumber=lineNumbers[index];if(!lineNumber){return;}
const lineHeight=lineHeights[index];if(lineHeight-baselineHeight>wrapThreshold){lineNumber.style.height=`${lineHeight}px`;lineNumber.style.lineHeight=`${baselineHeight}px`;return;}
lineNumber.style.height="";lineNumber.style.lineHeight="";});}
function setWrapEnabled(enabled){document.documentElement.classList.toggle(WRAP_ENABLED_CLASS,enabled);document.querySelectorAll(".highlight").forEach((highlight)=>{highlight.querySelector(`.${WRAP_VIEW_CLASS}`)?.remove();if(enabled&&highlight.dataset[WRAP_AVAILABLE_DATASET]==="true"){highlight.classList.add("site-code-wrap-is-enabled");return;}
highlight.classList.remove("site-code-wrap-is-enabled");clearWrappedLineNumbers(highlight);});if(enabled){window.requestAnimationFrame(()=>{document.querySelectorAll(".highlight.site-code-wrap-is-enabled").forEach(syncWrappedLineNumbers);});}
updateWrapButtons();}
function ensureWrapButton(nav){if(!nav||nav.querySelector(WRAP_BUTTON_SELECTOR)){return;}
const wrapButton=document.createElement("button");wrapButton.type="button";wrapButton.className="md-code__button site-code-wrap-button";wrapButton.innerHTML=`
            <svg viewBox="0 0 1194 1024" aria-hidden="true" focusable="false">
                <path d="M648.533333 819.2c0-25.6 34.133333-51.2 34.133334-51.2s145.066667-110.933333 162.133333-110.933333c34.133333 0 34.133333 25.6 34.133333 25.6v273.066666c0 25.6-17.066667 25.6-34.133333 25.6-8.533333 0-162.133333-110.933333-162.133333-110.933333s-34.133333-17.066667-34.133334-51.2zM0 819.2c0-25.6 25.6-51.2 51.2-51.2h384c34.133333 0 51.2 25.6 51.2 51.2 0 34.133333-25.6 51.2-51.2 51.2H51.2c-25.6 8.533333-51.2-17.066667-51.2-51.2z m0-384c0-34.133333 25.6-51.2 51.2-51.2h759.466667c34.133333 0 51.2 25.6 51.2 51.2 0 34.133333-25.6 51.2-51.2 51.2H51.2c-25.6 8.533333-51.2-17.066667-51.2-51.2zM0 51.2C0 25.6 25.6 0 51.2 0h1083.733333c34.133333 0 59.733333 25.6 59.733334 51.2 0 34.133333-25.6 51.2-51.2 51.2H51.2C25.6 110.933333 0 85.333333 0 51.2zM870.4 768h213.333333V435.2c0-34.133333 25.6-51.2 51.2-51.2 34.133333 0 51.2 25.6 51.2 51.2v384c0 34.133333-25.6 51.2-51.2 51.2h-273.066666V768z"></path>
            </svg>
        `;wrapButton.addEventListener("click",()=>{const isEnabled=document.documentElement.classList.contains(WRAP_ENABLED_CLASS);setWrapEnabled(!isEnabled);});const copyButton=nav.querySelector('.md-code__button[data-md-type="copy"]');if(copyButton){nav.insertBefore(wrapButton,copyButton);return;}
nav.appendChild(wrapButton);}
function syncCopyButtonSource(highlight){const copyButton=highlight.querySelector('.md-code__button[data-md-type="copy"]');const codeElement=getSourceTable(highlight)?.querySelector("td.code pre code");if(!copyButton||!codeElement){return;}
copyButton.setAttribute("data-clipboard-text",codeElement.textContent||"");copyButton.removeAttribute("data-clipboard-target");}
function isHighlightVisible(highlight){return!highlight.closest("[hidden]")&&highlight.getClientRects().length>0;}
function refreshWrapAvailability(options={}){const isWrapEnabled=document.documentElement.classList.contains(WRAP_ENABLED_CLASS);const highlights=Array.from(document.querySelectorAll(".highlight")).filter((highlight)=>{if(!options.visibleOnly){return true;}
return isHighlightVisible(highlight);});highlights.forEach((highlight)=>{const nav=moveCodeNavToHighlight(highlight);ensureWrapButton(nav);syncCopyButtonSource(highlight);highlight.querySelector(`.${WRAP_VIEW_CLASS}`)?.remove();normalizeLineNumberLayout(highlight);normalizeCodeLineWhitespace(highlight);const wrapButton=nav?.querySelector(WRAP_BUTTON_SELECTOR);const shouldPreserveEnabled=Boolean(options.preserveEnabled)&&isWrapEnabled&&highlight.classList.contains("site-code-wrap-is-enabled");if(!shouldPreserveEnabled){highlight.classList.remove("site-code-wrap-is-enabled");clearWrappedLineNumbers(highlight);}
const isOverflowing=shouldPreserveEnabled?true:hasHorizontalOverflow(highlight);highlight.dataset[WRAP_AVAILABLE_DATASET]=String(isOverflowing);if(wrapButton){wrapButton.hidden=!isOverflowing;}
if(isOverflowing&&isWrapEnabled){highlight.classList.add("site-code-wrap-is-enabled");}});if(isWrapEnabled){window.requestAnimationFrame(()=>{highlights.forEach((highlight)=>{if(highlight.classList.contains("site-code-wrap-is-enabled")){syncWrappedLineNumbers(highlight);}});});}
updateWrapButtons();}
refreshWrapAvailability();scheduleWrapAvailabilityRefresh(180);window.addEventListener("resize",()=>{scheduleWrapAvailabilityRefresh();});window.addEventListener("hashchange",()=>{scheduleWrapAvailabilityRefresh(160,{visibleOnly:true,preserveEnabled:true});});document.addEventListener("change",(event)=>{if(event.target instanceof HTMLInputElement&&event.target.closest(".tabbed-set")){scheduleWrapAvailabilityRefresh(160,{visibleOnly:true,preserveEnabled:true});}});document.querySelectorAll('.md-code__button[data-md-type="copy"]').forEach((button)=>{button.addEventListener("click",function(){const codeBlock=this.closest(".highlight");if(!codeBlock)return;const oldFlash=codeBlock.querySelector(".copy-flash");if(oldFlash){oldFlash.remove();}
const flash=document.createElement("div");flash.className="copy-flash";codeBlock.appendChild(flash);flash.addEventListener("animationend",()=>{flash.remove();});});});});function adjustTooltipPosition(){const tooltips=document.querySelectorAll('.custom-tooltip');tooltips.forEach(tooltip=>{tooltip.classList.remove('tooltip-left','tooltip-right');const rect=tooltip.getBoundingClientRect();const viewportWidth=window.innerWidth;const tooltipWidth=Math.min(300,viewportWidth-20);const rightOverflow=(rect.left+tooltipWidth/2)>(viewportWidth-10);const leftOverflow=(rect.left-tooltipWidth/2)<10;if(rightOverflow){tooltip.classList.add('tooltip-right');}else if(leftOverflow){tooltip.classList.add('tooltip-left');}
});}
document.addEventListener('DOMContentLoaded',adjustTooltipPosition);window.addEventListener('resize',adjustTooltipPosition);document.addEventListener('click',function(e){if(e.target.classList.contains('custom-tooltip')){setTimeout(adjustTooltipPosition,10);}});function updateActiveBorder(){document.querySelectorAll('.active-border').forEach(el=>{el.classList.remove('active-border');});let actives=document.querySelectorAll('.md-nav--secondary .md-nav__link--active');let active=actives[1];let active_parent=active&&active.parentNode;if(active&&active_parent){active_parent.classList.add('active-border');}}
document.addEventListener('DOMContentLoaded',updateActiveBorder);window.addEventListener('scroll',function(){clearTimeout(window.scrollTimer);window.scrollTimer=setTimeout(updateActiveBorder,5);});document.addEventListener('click',function(e){if(e.target.closest('.md-nav__link')){setTimeout(updateActiveBorder,5);}});